import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The visible question text." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Options for multiple choice. Empty for Speaking/Writing." 
          },
          correctAnswer: { type: Type.STRING, description: "Correct answer string." },
          explanation: { type: Type.STRING, description: "Vietnamese explanation." },
          topic: { type: Type.STRING },
          listeningScript: { type: Type.STRING, description: "Text for TTS to read (Listening mode only)." },
          speakingTarget: { type: Type.STRING, description: "Sentence to read aloud (Speaking mode only)." },
        },
        required: ["id", "questionText", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; 

  let specificInstruction = "";

  switch (gameType) {
    case GameType.Quiz:
    case GameType.FillBlank:
      specificInstruction = `Create 5 questions. For 'FillBlank', questionText should have a '_____' placeholder. Provide 4 options.`;
      break;
    case GameType.Listening:
      specificInstruction = `Create 3 listening challenges. 'listeningScript' is a short dialogue or sentence suitable for ${grade}. 'questionText' is a comprehension question about the script. Provide 4 options.`;
      break;
    case GameType.Speaking:
      specificInstruction = `Create 5 speaking challenges. 'questionText' is instruction (e.g., 'Read this sentence'). 'speakingTarget' is the English sentence the student must say. Make it curriculum appropriate.`;
      break;
    case GameType.Writing:
      specificInstruction = `Create 1 writing challenge. 'questionText' is the essay/paragraph prompt (e.g., 'Write about your best friend'). 'topic' is the genre.`;
      break;
  }

  const prompt = `
    Role: Expert English Teacher for Vietnam MOET Curriculum.
    Grade: ${grade}.
    Task: ${specificInstruction}
    Textbook Reference: ${specificTextbook || "Standard MOET Curriculum (Global Success, Friends Global, etc.)"}.

    Curriculum Focus:
    - Grade 1-5: Family, Colors, Animals, School, Simple Pres/Cont Tense.
    - Grade 6-9: Environment, Community, Travel, Past/Future Tenses, Conditionals.
    - Grade 10-12: Society, Technology, Careers, IELTS foundation topics, Advanced Grammar.

    Output: JSON. Ensure explanations are in Vietnamese.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

export const evaluateWriting = async (prompt: string, studentText: string, grade: string) => {
  const gradingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.INTEGER, description: "Score out of 100" },
      feedback: { type: Type.STRING, description: "Constructive feedback in Vietnamese" },
      corrections: { type: Type.STRING, description: "Corrected version of the text" }
    }
  };

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Grade this English writing for a ${grade} Vietnamese student.
    Prompt: ${prompt}
    Student Answer: "${studentText}"
    Provide score (0-100), helpful feedback in Vietnamese, and a corrected version.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: gradingSchema
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface ListeningGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  isPrimary: boolean;
}

export const ListeningGame: React.FC<ListeningGameProps> = ({ questions, onComplete, isPrimary }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);

  const current = questions[index];

  const playAudio = () => {
    if (!current.listeningScript) return;
    setIsPlaying(true);
    const utterance = new SpeechSynthesisUtterance(current.listeningScript);
    utterance.lang = 'en-US';
    utterance.rate = isPrimary ? 0.8 : 1.0; // Slower for kids
    utterance.onend = () => setIsPlaying(false);
    window.speechSynthesis.cancel(); // Clear queue
    window.speechSynthesis.speak(utterance);
  };

  const handleAnswer = (option: string) => {
    if (feedback) return;
    const isCorrect = option === current.correctAnswer;
    if (isCorrect) setScore(s => s + 1);
    setFeedback(isCorrect ? "Correct! 🎉" : `Incorrect. Answer: ${current.correctAnswer}`);

    setTimeout(() => {
      setFeedback(null);
      if (index < questions.length - 1) setIndex(i => i + 1);
      else onComplete(score + (isCorrect ? 1 : 0));
    }, 2000);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="text-center mb-8">
        <h3 className="text-xl font-bold text-gray-600 mb-4">Luyện Nghe (Question {index + 1}/{questions.length})</h3>
        <button 
          onClick={playAudio}
          disabled={isPlaying}
          className={`rounded-full p-6 transition-all ${isPlaying ? 'bg-gray-200' : 'bg-blue-100 hover:bg-blue-200 text-blue-600'}`}
        >
          <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
          </svg>
        </button>
        <p className="mt-2 text-sm text-gray-500">{isPlaying ? "Đang đọc..." : "Bấm để nghe"}</p>
      </div>

      <div className="mb-6">
        <p className="text-lg font-medium text-gray-800">{current.questionText}</p>
      </div>

      <div className="grid gap-3">
        {current.options?.map((opt, i) => (
          <Button key={i} onClick={() => handleAnswer(opt)} variant="outline" fullWidth disabled={!!feedback}>
            {opt}
          </Button>
        ))}
      </div>

      {feedback && (
        <div className={`mt-4 p-4 rounded-xl text-center font-bold ${feedback.includes('Correct') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
          {feedback}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface SpeakingGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const SpeakingGame: React.FC<SpeakingGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [feedback, setFeedback] = useState<string | null>(null);

  const current = questions[index];

  // @ts-ignore - simple handling for webkitSpeechRecognition
  const Recognition = window.SpeechRecognition || window.webkitSpeechRecognition;

  const handleRecord = () => {
    if (!Recognition) {
      alert("Trình duyệt của bạn không hỗ trợ nhận diện giọng nói (thử Chrome).");
      return;
    }

    const recognition = new Recognition();
    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    setIsListening(true);
    setTranscript("");
    setFeedback(null);

    recognition.start();

    recognition.onresult = (event: any) => {
      const text = event.results[0][0].transcript;
      setTranscript(text);
      checkPronunciation(text);
    };

    recognition.onerror = () => {
      setIsListening(false);
      setFeedback("Không nghe rõ, thử lại nhé!");
    };

    recognition.onend = () => setIsListening(false);
  };

  const checkPronunciation = (spoken: string) => {
    const target = current.speakingTarget || "";
    // Simple normalization check
    const normalize = (s: string) => s.toLowerCase().replace(/[.,!?]/g, '').trim();

    if (normalize(spoken) === normalize(target)) {
      setFeedback("Tuyệt vời! Chính xác 100%");
      setScore(s => s + 1);
      setTimeout(nextQuestion, 2000);
    } else {
      setFeedback(`Gần đúng! Bạn nói: "${spoken}"`);
    }
  };

  const nextQuestion = () => {
    setFeedback(null);
    setTranscript("");
    if (index < questions.length - 1) setIndex(i => i + 1);
    else onComplete(score);
  };

  if (!Recognition) return <div className="text-center p-8">Trình duyệt không hỗ trợ Speaking.</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl text-center">
      <span className="text-sm font-bold text-gray-400">Câu {index + 1}/{questions.length}</span>
      <h3 className="text-2xl font-bold text-gray-800 mt-2 mb-6">{current.questionText}</h3>

      <div className="bg-blue-50 p-6 rounded-2xl mb-8 border-2 border-blue-100">
        <p className="text-3xl font-extrabold text-blue-600">{current.speakingTarget}</p>
      </div>

      <div className="mb-8 h-12">
        {transcript && <p className="text-gray-500 italic">"{transcript}"</p>}
        {feedback && <p className={`font-bold ${feedback.includes('Tuyệt') ? 'text-green-600' : 'text-orange-500'}`}>{feedback}</p>}
      </div>

      <div className="flex gap-4 justify-center">
        <Button 
          onClick={handleRecord} 
          disabled={isListening}
          variant={isListening ? 'danger' : 'primary'}
          size="lg"
          className="rounded-full w-20 h-20 flex items-center justify-center"
        >
          {isListening ? (
             <span className="animate-pulse bg-white w-4 h-4 rounded-full"></span>
          ) : (
            <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          )}
        </Button>
      </div>

      <div className="mt-8 flex justify-center">
        <Button onClick={nextQuestion} variant="outline" size="sm">Bỏ qua (Skip)</Button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { QuestionData, GradeLevel } from '../types';
import { Button } from './Button';
import { evaluateWriting } from '../services/geminiService';

interface WritingGameProps {
  questions: QuestionData[];
  grade: GradeLevel;
  onComplete: (score: number) => void;
}

export const WritingGame: React.FC<WritingGameProps> = ({ questions, grade, onComplete }) => {
  const [input, setInput] = useState("");
  const [isGrading, setIsGrading] = useState(false);
  const [result, setResult] = useState<{score: number, feedback: string, corrections: string} | null>(null);

  const current = questions[0]; // Writing usually has 1 big task

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setIsGrading(true);
    try {
      const evalResult = await evaluateWriting(current.questionText, input, grade);
      setResult(evalResult);
    } catch (e) {
      alert("Error grading. Try again.");
    } finally {
      setIsGrading(false);
    }
  };

  if (result) {
    return (
      <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
        <h2 className="text-3xl font-bold text-center mb-6 text-blue-800">Kết quả bài viết</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
           <div className="bg-blue-50 p-4 rounded-xl">
             <p className="text-sm text-blue-600 font-bold uppercase">Điểm số</p>
             <p className="text-5xl font-black text-blue-900">{result.score}/100</p>
           </div>
           <div className="bg-green-50 p-4 rounded-xl">
             <p className="text-sm text-green-600 font-bold uppercase">Feedback</p>
             <p className="text-gray-700">{result.feedback}</p>
           </div>
        </div>
        <div className="bg-yellow-50 p-4 rounded-xl mb-8">
           <p className="font-bold text-yellow-800 mb-2">Gợi ý sửa đổi:</p>
           <p className="italic text-gray-700">{result.corrections}</p>
        </div>
        <Button onClick={() => onComplete(result.score > 50 ? 5 : 0)} fullWidth size="lg">Hoàn thành</Button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="mb-6">
        <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">{current.topic}</span>
        <h3 className="text-2xl font-bold text-gray-800 mt-3">{current.questionText}</h3>
        {current.writingPrompt && <p className="text-gray-600 mt-2">{current.writingPrompt}</p>}
      </div>

      <textarea 
        className="w-full h-64 p-4 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-0 text-lg resize-none mb-6"
        placeholder="Type your answer here..."
        value={input}
        onChange={(e) => setInput(e.target.value)}
      />

      <div className="flex justify-end">
        <Button 
          onClick={handleSubmit} 
          disabled={isGrading || input.length < 10} 
          size="lg"
          variant="primary"
        >
          {isGrading ? 'Đang chấm điểm...' : 'Nộp bài (Submit)'}
        </Button>
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { Button } from './Button';
import { MOTIVATIONAL_MESSAGES } from '../constants';

interface ResultCardProps {
  score: number;
  total: number;
  onRetry: () => void;
  onHome: () => void;
}

export const ResultCard: React.FC<ResultCardProps> = ({ score, total, onRetry, onHome }) => {
  const percentage = Math.round((score / total) * 100);

  // Simple badges based on performance
  const badges = [
    { name: "Star Student", icon: "⭐", condition: percentage === 100 },
    { name: "Hard Worker", icon: "📚", condition: percentage >= 50 },
  ];

  const earnedBadges = badges.filter(b => b.condition);

  let message = "";
  if (percentage === 100) message = "Xuất sắc! (Perfect!) 🌟";
  else if (percentage >= 80) message = MOTIVATIONAL_MESSAGES[0];
  else if (percentage >= 60) message = MOTIVATIONAL_MESSAGES[1];
  else message = "Cố gắng hơn nữa nhé! (Try again!) 💪";

  // Persist score helper (simplified for demo)
  useEffect(() => {
    const currentPoints = parseInt(localStorage.getItem('vieteng_points') || '0');
    localStorage.setItem('vieteng_points', (currentPoints + score).toString());
  }, [score]);

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl max-w-md w-full mx-auto text-center border-4 border-yellow-400 animate-fade-in-up">
      <div className="mb-6">
        <h2 className="text-3xl font-extrabold text-gray-800 mt-4">Kết Quả</h2>
        <p className="text-gray-500 text-lg">Results</p>
      </div>

      <div className="relative inline-block mb-6">
         <div className="text-7xl font-black text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-purple-600">
            {score}/{total}
         </div>
      </div>

      <p className="text-xl text-orange-500 font-bold mb-8">{message}</p>

      {/* Badge Section */}
      {earnedBadges.length > 0 && (
        <div className="bg-yellow-50 rounded-xl p-4 mb-8">
          <p className="text-xs font-bold text-yellow-700 uppercase mb-2">Huy hiệu nhận được</p>
          <div className="flex justify-center gap-4">
            {earnedBadges.map(badge => (
              <div key={badge.name} className="flex flex-col items-center animate-bounce">
                <span className="text-4xl">{badge.icon}</span>
                <span className="text-xs font-bold text-gray-600 mt-1">{badge.name}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="space-y-3">
        <Button onClick={onRetry} fullWidth variant="primary" size="lg">
          Chơi lại (Play Again)
