import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData, GrammarSubSkill } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The visible question text." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Options for multiple choice. Empty for Speaking/Writing/Sentence Transformation." 
          },
          correctAnswer: { type: Type.STRING, description: "Correct answer string." },
          explanation: { type: Type.STRING, description: "Vietnamese explanation." },
          topic: { type: Type.STRING },
          listeningScript: { type: Type.STRING, description: "Text for TTS to read. Use 'Speaker: Text' format for dialogues. Ensure proper punctuation (. ! ?)." },
          speakingTarget: { type: Type.STRING, description: "Sentence to read aloud (Speaking mode only)." },
        },
        required: ["id", "questionText", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string,
  subSkill?: GrammarSubSkill
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; 

  let specificInstruction = "";

  // Define grade-based difficulty instructions
  const gradeLevelInstruction = parseInt(grade.replace('Grade ', '')) <= 9 
    ? "Difficulty: Secondary School (A1-A2/B1). Focus on fundamental tenses (Present/Past/Future), comparisons, modals, basic prepositions, and daily vocabulary."
    : "Difficulty: High School (B1+/B2). Focus on advanced tenses, inversion, subjunctive, phrasal verbs, collocations, idioms, and academic vocabulary.";

  switch (gameType) {
    case GameType.Grammar:
      if (subSkill) {
        switch (subSkill) {
          case GrammarSubSkill.Pronunciation:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Pronunciation.
            Format: Give a list of 4 words as options. The 'questionText' should be: "Choose the word whose underlined part is pronounced differently from the others." 
            IMPORTANT: In the 'options', wrap the specific phoneme part in parentheses e.g. "h(a)t".`;
            break;
          case GrammarSubSkill.Stress:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Word Stress.
            Format: Give 4 words. The 'questionText' should be: "Choose the word that has a different stress pattern from the others."`;
            break;
          case GrammarSubSkill.GrammarQuiz:
            specificInstruction = `Create 10 Multiple Choice Questions covering general grammar points suitable for ${grade}.
            Includes tenses, prepositions, articles, conjunctions.`;
            break;
          case GrammarSubSkill.FillBlank:
            specificInstruction = `Create 10 Multiple Choice Questions (Cloze style).
            'questionText' must contain a '______' placeholder. Provide 4 options to fill the blank.`;
            break;
          case GrammarSubSkill.Synonym:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Synonyms (CLOSEST in meaning).
            'questionText' should be a sentence with a CAPITALIZED word. Ask for the word CLOSEST in meaning.`;
            break;
          case GrammarSubSkill.Antonym:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Antonyms (OPPOSITE in meaning).
            'questionText' should be a sentence with a CAPITALIZED word. Ask for the word OPPOSITE in meaning.`;
            break;
          case GrammarSubSkill.Paragraph:
            specificInstruction = `Create 10 Questions based on a short paragraph context.
            However, present them as individual sentences with blanks related to a cohesive topic (e.g., Environment, Technology).
            'questionText' should have a blank. Options should be transition words or context-dependent vocabulary.`;
            break;
          case GrammarSubSkill.WordForm:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Word Forms (Noun, Verb, Adjective, Adverb).
            'questionText': A sentence with a blank. Options: 4 variations of the same root word (e.g., beauty, beautiful, beautifully, beautify).`;
            break;
          case GrammarSubSkill.SentenceTrans:
            specificInstruction = `Create 10 Sentence Transformation Questions. Topic: Sentence Transformation.
            'questionText': Provide the original sentence AND the starting words of the new sentence (e.g., "I haven't seen him for two years. -> The last time...").
            'correctAnswer': The FULL correct rewritten sentence (e.g., "The last time I saw him was two years ago").
            'options': Leave empty array [].`;
            break;
          default:
            specificInstruction = `Create 10 grammar Multiple Choice Questions.`;
        }
      } else {
        specificInstruction = `Create 10 mixed grammar Multiple Choice Questions.`;
      }
      break;

    case GameType.Listening:
      specificInstruction = `Create 3 listening challenges. 'listeningScript' MUST be a dialogue (e.g., 'Mom: Time for bed!\nTom: Not yet.') or a short story. Ensure distinct speakers and emotions. 'questionText' is a comprehension question with 4 options. ${gradeLevelInstruction}`;
      break;
    case GameType.Speaking:
      specificInstruction = `Create 5 speaking challenges. 'questionText' is instruction (e.g., 'Read this sentence'). 'speakingTarget' is the English sentence the student must say. ${gradeLevelInstruction}`;
      break;
    case GameType.Writing:
      specificInstruction = `Create 1 writing challenge. 'questionText' is the essay/paragraph prompt (e.g., 'Write about your best friend'). 'topic' is the genre. ${gradeLevelInstruction}`;
      break;
  }

  const prompt = `
    Role: Expert English Teacher for Vietnam MOET Curriculum (Secondary & High School).
    Grade: ${grade}.
    Task: ${specificInstruction}
    Textbook Reference: ${specificTextbook || "Standard MOET Curriculum (Global Success, Friends Global, etc.)"}.

    ${gradeLevelInstruction}

    Output: JSON. Ensure explanations are in Vietnamese and explain clearly why the answer is correct based on grammar rules.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

export const evaluateWriting = async (prompt: string, studentText: string, grade: string) => {
  const gradingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.INTEGER, description: "Score out of 20" },
      feedback: { type: Type.STRING, description: "Constructive feedback in Vietnamese" },
      corrections: { type: Type.STRING, description: "Corrected version of the text" }
    }
  };

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Grade this English writing for a ${grade} Vietnamese student.
    Prompt: ${prompt}
    Student Answer: "${studentText}"
    Provide score (0-20), helpful feedback in Vietnamese, and a corrected version.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: gradingSchema
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState, useEffect } from 'react';
import { QuestionData, GrammarSubSkill } from '../types';
import { Button } from './Button';

interface QuizGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  subSkill?: GrammarSubSkill;
}

export const QuizGame: React.FC<QuizGameProps> = ({ questions, onComplete, subSkill }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Input mode state
  const [userInput, setUserInput] = useState("");
  const [isInputCorrect, setIsInputCorrect] = useState<boolean | null>(null);
  const [showSuggestion, setShowSuggestion] = useState(false);

  const currentQuestion = questions[currentIndex];
  const isInputMode = subSkill === GrammarSubSkill.SentenceTrans;

  // Reset state on question change
  useEffect(() => {
    setSelectedOption(null);
    setShowFeedback(false);
    setUserInput("");
    setIsInputCorrect(null);
    setShowSuggestion(false);
  }, [currentIndex]);

  const handleOptionClick = (option: string) => {
    if (showFeedback) return;

    setSelectedOption(option);
    setShowFeedback(true);

    if (option === currentQuestion.correctAnswer) {
      setScore(prev => prev + 2); // 2 points per correct answer
    }
  };

  const handleInputCheck = () => {
    if (showFeedback) return;

    const normalize = (s: string) => s.toLowerCase().replace(/[.,!?;:]/g, '').trim().replace(/\s+/g, ' ');
    const user = normalize(userInput);
    const correct = normalize(currentQuestion.correctAnswer || "");

    const isCorrect = user === correct;
    setIsInputCorrect(isCorrect);
    setShowFeedback(true);

    if (isCorrect) {
      setScore(prev => prev + 2);
    }
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onComplete(score);
    }
  };

  const getButtonVariant = (option: string) => {
    if (!showFeedback) return selectedOption === option ? 'primary' : 'outline';
    if (option === currentQuestion.correctAnswer) return 'primary'; 
    if (option === selectedOption && option !== currentQuestion.correctAnswer) return 'danger';
    return 'outline';
  };

  const getButtonStyle = (option: string) => {
    if (!showFeedback) return "";
    if (option === currentQuestion.correctAnswer) return "!bg-green-500 !border-green-700 !text-white";
    return "";
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      {/* Progress Bar */}
      <div className="mb-6 bg-gray-200 rounded-full h-4 overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 border-b-8 border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <span className="bg-blue-100 text-blue-800 text-xs font-bold px-3 py-1 rounded-full uppercase">
            Question {currentIndex + 1}/{questions.length}
          </span>
          <span className="text-gray-400 font-bold text-sm">{currentQuestion.topic}</span>
        </div>

        <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-8 leading-relaxed text-center">
          {currentQuestion.questionText}
        </h3>

        {/* RENDER FOR INPUT MODE (Sentence Transformation) */}
        {isInputMode ? (
          <div className="mb-6 space-y-4">
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              disabled={showFeedback}
              placeholder="Type your rewritten sentence here..."
              className={`w-full p-4 text-lg border-2 rounded-xl focus:ring-0 focus:border-blue-500 transition-colors resize-none h-32 ${
                isInputCorrect === true ? 'border-green-500 bg-green-50' : 
                isInputCorrect === false ? 'border-red-500 bg-red-50' : 
                'border-gray-300'
              }`}
            />

            {!showFeedback && (
              <div className="flex gap-3">
                 <Button onClick={handleInputCheck} disabled={!userInput.trim()} variant="primary" fullWidth>
                    Kiểm tra (Check)
                 </Button>
                 <Button 
                   onClick={() => setShowSuggestion(true)} 
                   variant="secondary" 
                   className="bg-yellow-500 hover:bg-yellow-600 border-yellow-700"
                 >
                    Gợi ý (Suggest) 💡
                 </Button>
              </div>
            )}

            {showSuggestion && !showFeedback && (
              <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-xl animate-fade-in">
                <p className="text-yellow-800 font-bold mb-1">Gợi ý đáp án (Suggested Answer):</p>
                <p className="text-gray-700 italic select-all">{currentQuestion.correctAnswer}</p>
                <p className="text-xs text-yellow-600 mt-2">* Bạn có thể sao chép đáp án này nếu quá khó (You can copy this answer).</p>
              </div>
            )}

            {showFeedback && isInputCorrect === false && (
              <div className="bg-red-50 border border-red-200 p-4 rounded-xl">
                 <p className="text-red-700 font-bold">Đáp án đúng (Correct Answer):</p>
                 <p className="text-gray-800 text-lg">{currentQuestion.correctAnswer}</p>
              </div>
            )}
          </div>
        ) : (
        /* RENDER FOR MULTIPLE CHOICE */
          <div className="grid grid-cols-1 gap-4 mb-6">
            {currentQuestion.options?.map((option, idx) => (
              <Button
                key={idx}
                variant={getButtonVariant(option)}
                className={`text-left justify-start h-auto py-4 px-6 text-lg ${getButtonStyle(option)}`}
                onClick={() => handleOptionClick(option)}
                fullWidth
              >
                {option}
              </Button>
            ))}
          </div>
        )}

        {showFeedback && (
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-6 animate-fade-in">
            <p className="font-bold text-blue-800 mb-1">Giải thích (Explanation):</p>
            <p className="text-blue-700">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="flex justify-end">
          <Button 
            disabled={!showFeedback} 
            onClick={handleNext}
            size="lg"
            variant="secondary"
          >
            {currentIndex === questions.length - 1 ? 'Kết thúc (Finish)' : 'Câu tiếp theo (Next) →'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { QuestionData, GradeLevel } from '../types';
import { Button } from './Button';
import { evaluateWriting } from '../services/geminiService';

interface WritingGameProps {
  questions: QuestionData[];
  grade: GradeLevel;
  onComplete: (score: number) => void;
}

export const WritingGame: React.FC<WritingGameProps> = ({ questions, grade, onComplete }) => {
  const [input, setInput] = useState("");
  const [isGrading, setIsGrading] = useState(false);
  const [result, setResult] = useState<{score: number, feedback: string, corrections: string} | null>(null);

  const current = questions[0]; // Writing usually has 1 big task

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setIsGrading(true);
    try {
      const evalResult = await evaluateWriting(current.questionText, input, grade);
      setResult(evalResult);
    } catch (e) {
      alert("Error grading. Try again.");
    } finally {
      setIsGrading(false);
    }
  };

  if (result) {
    return (
      <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
        <h2 className="text-3xl font-bold text-center mb-6 text-blue-800">Kết quả bài viết</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
           <div className="bg-blue-50 p-4 rounded-xl">
             <p className="text-sm text-blue-600 font-bold uppercase">Điểm số</p>
             <p className="text-5xl font-black text-blue-900">{result.score}/20</p>
           </div>
           <div className="bg-green-50 p-4 rounded-xl">
             <p className="text-sm text-green-600 font-bold uppercase">Feedback</p>
             <p className="text-gray-700">{result.feedback}</p>
           </div>
        </div>
        <div className="bg-yellow-50 p-4 rounded-xl mb-8">
           <p className="font-bold text-yellow-800 mb-2">Gợi ý sửa đổi:</p>
           <p className="italic text-gray-700">{result.corrections}</p>
        </div>
        <Button onClick={() => onComplete(result.score)} fullWidth size="lg">Hoàn thành</Button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="mb-6">
        <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">{current.topic}</span>
        <h3 className="text-2xl font-bold text-gray-800 mt-3">{current.questionText}</h3>
        {current.writingPrompt && <p className="text-gray-600 mt-2">{current.writingPrompt}</p>}
      </div>

      <textarea 
        className="w-full h-64 p-4 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-0 text-lg resize-none mb-6"
        placeholder="Type your answer here..."
        value={input}
        onChange={(e) => setInput(e.target.value)}
      />

      <div className="flex justify-end">
        <Button 
          onClick={handleSubmit} 
          disabled={isGrading || input.length < 10} 
          size="lg"
          variant="primary"
        >
          {isGrading ? 'Đang chấm điểm...' : 'Nộp bài (Submit)'}
        </Button>
      </div>
    </div>
  );
};

