import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData, GrammarSubSkill } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The visible question text." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Options for multiple choice. Empty for Speaking/Writing/Sentence Transformation." 
          },
          correctAnswer: { type: Type.STRING, description: "Correct answer string." },
          explanation: { type: Type.STRING, description: "Vietnamese explanation." },
          topic: { type: Type.STRING },
          listeningScript: { type: Type.STRING, description: "Text for TTS to read. Use 'Speaker: Text' format for dialogues. Ensure proper punctuation (. ! ?)." },
          speakingTarget: { type: Type.STRING, description: "Sentence to read aloud (Speaking mode only)." },
        },
        required: ["id", "questionText", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string,
  subSkill?: GrammarSubSkill
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; 

  let specificInstruction = "";

  // Define grade-based difficulty instructions
  const gradeLevelInstruction = parseInt(grade.replace('Grade ', '')) <= 9 
    ? "Difficulty: Secondary School (A1-A2/B1). Focus on fundamental tenses (Present/Past/Future), comparisons, modals, basic prepositions, and daily vocabulary."
    : "Difficulty: High School (B1+/B2). Focus on advanced tenses, inversion, subjunctive, phrasal verbs, collocations, idioms, and academic vocabulary.";

  switch (gameType) {
    case GameType.Grammar:
      if (subSkill) {
        switch (subSkill) {
          case GrammarSubSkill.Pronunciation:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Pronunciation.
            Format: Give a list of 4 words as options. The 'questionText' should be: "Choose the word whose underlined part is pronounced differently from the others." 
            IMPORTANT: In the 'options', wrap the specific phoneme part in parentheses e.g. "h(a)t".`;
            break;
          case GrammarSubSkill.Stress:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Word Stress.
            Format: Give 4 words. The 'questionText' should be: "Choose the word that has a different stress pattern from the others."`;
            break;
          case GrammarSubSkill.GrammarQuiz:
            specificInstruction = `Create 10 Multiple Choice Questions covering general grammar points suitable for ${grade}.
            Includes tenses, prepositions, articles, conjunctions.`;
            break;
          case GrammarSubSkill.FillBlank:
            specificInstruction = `Create 10 Multiple Choice Questions (Cloze style).
            'questionText' must contain a '______' placeholder. Provide 4 options to fill the blank.`;
            break;
          case GrammarSubSkill.Synonym:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Synonyms (CLOSEST in meaning).
            'questionText' should be a sentence with a CAPITALIZED word. Ask for the word CLOSEST in meaning.`;
            break;
          case GrammarSubSkill.Antonym:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Antonyms (OPPOSITE in meaning).
            'questionText' should be a sentence with a CAPITALIZED word. Ask for the word OPPOSITE in meaning.`;
            break;
          case GrammarSubSkill.Paragraph:
            specificInstruction = `Create 10 Questions based on a short paragraph context.
            However, present them as individual sentences with blanks related to a cohesive topic (e.g., Environment, Technology).
            'questionText' should have a blank. Options should be transition words or context-dependent vocabulary.`;
            break;
          case GrammarSubSkill.WordForm:
            specificInstruction = `Create 10 Multiple Choice Questions. Topic: Word Forms (Noun, Verb, Adjective, Adverb).
            'questionText': A sentence with a blank. Options: 4 variations of the same root word (e.g., beauty, beautiful, beautifully, beautify).`;
            break;
          case GrammarSubSkill.SentenceTrans:
            specificInstruction = `Create 10 Sentence Transformation Questions. Topic: Sentence Transformation.
            'questionText': Provide the original sentence AND the starting words of the new sentence (e.g., "I haven't seen him for two years. -> The last time...").
            'correctAnswer': The FULL correct rewritten sentence (e.g., "The last time I saw him was two years ago").
            'options': Leave empty array [].`;
            break;
          default:
            specificInstruction = `Create 10 grammar Multiple Choice Questions.`;
        }
      } else {
        specificInstruction = `Create 10 mixed grammar Multiple Choice Questions.`;
      }
      break;

    case GameType.Listening:
      specificInstruction = `Create 3 listening challenges. 'listeningScript' MUST be a dialogue (e.g., 'Mom: Time for bed!\nTom: Not yet.') or a short story. Ensure distinct speakers and emotions. 'questionText' is a comprehension question with 4 options. ${gradeLevelInstruction}`;
      break;
    case GameType.Speaking:
      specificInstruction = `Create 5 speaking challenges. 'questionText' is instruction (e.g., 'Read this sentence'). 'speakingTarget' is the English sentence the student must say. ${gradeLevelInstruction}`;
      break;
    case GameType.Writing:
      specificInstruction = `Create 1 writing challenge. 
      'questionText' must be the essay prompt followed by 3-4 bullet points (suggestions) on what to include. 
      Format: "Write a paragraph about [Topic].\n- Suggestion 1\n- Suggestion 2\n- Suggestion 3". 
      'topic' is the genre. ${gradeLevelInstruction}`;
      break;
  }

  const prompt = `
    Role: Expert English Teacher for Vietnam MOET Curriculum (Secondary & High School).
    Grade: ${grade}.
    Task: ${specificInstruction}
    Textbook Reference: ${specificTextbook || "Standard MOET Curriculum (Global Success, Friends Global, etc.)"}.

    ${gradeLevelInstruction}

    Output: JSON. Ensure explanations are in Vietnamese and explain clearly why the answer is correct based on grammar rules.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

export const evaluateWriting = async (prompt: string, studentText: string, grade: string) => {
  const gradingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.INTEGER, description: "Score out of 20" },
      feedback: { type: Type.STRING, description: "Constructive feedback in Vietnamese" },
      corrections: { type: Type.STRING, description: "Corrected version of the text" }
    }
  };

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Grade this English writing for a ${grade} Vietnamese student.
    Prompt: ${prompt}
    Student Answer: "${studentText}"
    Provide score (0-20), helpful feedback in Vietnamese, and a corrected version.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: gradingSchema
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState } from 'react';
import { QuestionData, GradeLevel } from '../types';
import { Button } from './Button';
import { evaluateWriting } from '../services/geminiService';

interface WritingGameProps {
  questions: QuestionData[];
  grade: GradeLevel;
  onComplete: (score: number) => void;
}

export const WritingGame: React.FC<WritingGameProps> = ({ questions, grade, onComplete }) => {
  const [input, setInput] = useState("");
  const [isGrading, setIsGrading] = useState(false);
  const [result, setResult] = useState<{score: number, feedback: string, corrections: string} | null>(null);

  const current = questions[0]; // Writing usually has 1 big task

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setIsGrading(true);
    try {
      const evalResult = await evaluateWriting(current.questionText, input, grade);
      setResult(evalResult);
    } catch (e) {
      alert("Error grading. Try again.");
    } finally {
      setIsGrading(false);
    }
  };

  // Helper to render text with bullet points cleanly
  const renderPrompt = (text: string) => {
    // Split by newlines
    const lines = text.split('\n').filter(line => line.trim().length > 0);

    return (
      <div className="space-y-3">
        {lines.map((line, idx) => {
          const trimmed = line.trim();
          // Check if it's a list item (starts with -, *, or "1.")
          if (trimmed.startsWith('-') || trimmed.startsWith('*') || /^\d+\./.test(trimmed)) {
            return (
              <div key={idx} className="flex items-start pl-4 text-blue-800 font-medium">
                <span className="mr-3 text-blue-500 mt-1.5 flex-shrink-0">
                  <svg className="w-2 h-2" fill="currentColor" viewBox="0 0 8 8"><circle cx="4" cy="4" r="3" /></svg>
                </span>
                <span>{trimmed.replace(/^[-*]\s*/, '')}</span>
              </div>
            );
          }
          // Main header/topic
          return <h3 key={idx} className="text-2xl font-bold text-gray-800">{line}</h3>;
        })}
      </div>
    );
  };

  if (result) {
    return (
      <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
        <h2 className="text-3xl font-bold text-center mb-6 text-blue-800">Kết quả bài viết</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
           <div className="bg-blue-50 p-4 rounded-xl">
             <p className="text-sm text-blue-600 font-bold uppercase">Điểm số</p>
             <p className="text-5xl font-black text-blue-900">{result.score}/20</p>
           </div>
           <div className="bg-green-50 p-4 rounded-xl">
             <p className="text-sm text-green-600 font-bold uppercase">Feedback</p>
             <p className="text-gray-700">{result.feedback}</p>
           </div>
        </div>
        <div className="bg-yellow-50 p-4 rounded-xl mb-8">
           <p className="font-bold text-yellow-800 mb-2">Gợi ý sửa đổi:</p>
           <p className="italic text-gray-700">{result.corrections}</p>
        </div>
        <Button onClick={() => onComplete(result.score)} fullWidth size="lg">Hoàn thành</Button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="mb-6">
        <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider mb-4 inline-block">{current.topic}</span>

        {/* Render formatted prompt */}
        <div className="bg-blue-50/50 p-6 rounded-2xl border-2 border-blue-100 mb-6">
          {renderPrompt(current.questionText)}
        </div>

        {current.writingPrompt && <p className="text-gray-500 italic text-sm">{current.writingPrompt}</p>}
      </div>

      <textarea 
        className="w-full h-64 p-4 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-0 text-lg resize-none mb-6 font-medium text-gray-700"
        placeholder="Type your answer here..."
        value={input}
        onChange={(e) => setInput(e.target.value)}
      />

      <div className="flex justify-end">
        <Button 
          onClick={handleSubmit} 
          disabled={isGrading || input.length < 10} 
          size="lg"
          variant="primary"
        >
          {isGrading ? 'Đang chấm điểm...' : 'Nộp bài (Submit)'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface SpeakingGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const SpeakingGame: React.FC<SpeakingGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [feedback, setFeedback] = useState<string | null>(null);

  const recognitionRef = useRef<any>(null);
  const shouldListenRef = useRef<boolean>(false); // Helper to track intent

  const current = questions[index];

  // @ts-ignore - simple handling for webkitSpeechRecognition
  const Recognition = window.SpeechRecognition || window.webkitSpeechRecognition;

  useEffect(() => {
    // Cleanup on unmount or question change
    if (recognitionRef.current) {
      shouldListenRef.current = false; // Stop the auto-restart loop
      recognitionRef.current.stop();
      setIsListening(false);
    }
  }, [index]);

  const toggleRecord = () => {
    if (isListening) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const startRecording = () => {
    if (!Recognition) {
      alert("Trình duyệt của bạn không hỗ trợ nhận diện giọng nói (hãy thử dùng Google Chrome).");
      return;
    }

    // Indicate that we INTEND to listen, so if it stops randomly, we restart
    shouldListenRef.current = true;

    const recognition = new Recognition();
    recognition.lang = 'en-US';
    // Continuous allows it to not stop after a short pause
    recognition.continuous = true;
    // Interim results allows us to see what is being said in real-time
    recognition.interimResults = true;
    recognition.maxAlternatives = 1;

    recognitionRef.current = recognition;

    setIsListening(true);
    if (!transcript) setTranscript(""); 
    setFeedback("Đang lắng nghe... (Listening...)");

    try {
      recognition.start();
    } catch (e) {
      console.error(e);
      setIsListening(false);
      setFeedback("Lỗi khởi động micro. Vui lòng tải lại trang.");
    }

    recognition.onresult = (event: any) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          finalTranscript += event.results[i][0].transcript;
        } else {
          interimTranscript += event.results[i][0].transcript;
        }
      }

      // Update display with current best guess
      const currentText = finalTranscript || interimTranscript;
      setTranscript(currentText);

      // Check automatically if the user has said the target sentence correctly
      if (checkMatch(currentText)) {
          // Keep listening flag true so UI doesn't jump, but handle success logic
          stopRecording(true); // Success stop
      }
    };

    recognition.onerror = (event: any) => {
      console.error("Speech Recognition Error:", event.error);
      if (event.error === 'no-speech') {
        // Ignore no-speech errors in continuous mode usually
        return; 
      }

      // Only show error feedback if we are actually trying to listen
      if (shouldListenRef.current) {
          if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
            setFeedback("Vui lòng cấp quyền truy cập Micro trên trình duyệt!");
            shouldListenRef.current = false;
            setIsListening(false);
          } else if (event.error === 'audio-capture') {
            setFeedback("Không tìm thấy Micro. Vui lòng kiểm tra thiết bị.");
            shouldListenRef.current = false;
            setIsListening(false);
          } else if (event.error === 'network') {
             setFeedback("Lỗi kết nối mạng.");
             shouldListenRef.current = false;
             setIsListening(false);
          }
      }
    };

    recognition.onend = () => {
        // Critical: If we didn't mean to stop (intent is true), restart immediately.
        // This fixes the issue where browser stops listening when user pauses too long.
        if (shouldListenRef.current) {
            try {
                recognition.start();
            } catch (e) {
                // Ignore start errors (like if it's already started)
            }
        } else {
            setIsListening(false);
        }
    };
  };

  const stopRecording = (isSuccess = false) => {
    // Set intent to false so onend doesn't restart
    shouldListenRef.current = false;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null; // Don't nullify immediately to allow graceful shutdown
    }
    setIsListening(false);

    if (!isSuccess) {
        // If manually stopped, check the final transcript
        checkPronunciation(transcript);
    }
  };

  const normalizeText = (s: string) => s.toLowerCase().replace(/[.,!?]/g, '').trim();

  const checkMatch = (spoken: string): boolean => {
    const target = current.speakingTarget || "";
    const nSpoken = normalizeText(spoken);
    const nTarget = normalizeText(target);

    // Check for exact match or if the target is contained within spoken text (relaxed)
    return nSpoken.includes(nTarget) || nTarget.includes(nSpoken);
  };

  const checkPronunciation = (spoken: string) => {
    if (checkMatch(spoken)) {
      setFeedback("Tuyệt vời! Chính xác 100% 🎉");
      setScore(s => s + 2); // 2 Points
      setTimeout(nextQuestion, 2000);
    } else {
      setFeedback(`Gần đúng! Bạn nói: "${spoken || '...'}" - Hãy thử lại!`);
    }
  };

  const nextQuestion = () => {
    setFeedback(null);
    setTranscript("");
    if (index < questions.length - 1) setIndex(i => i + 1);
    else onComplete(score);
  };

  if (!Recognition) return <div className="text-center p-8">Trình duyệt không hỗ trợ Speaking.</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl text-center">
      <span className="text-sm font-bold text-gray-400">Câu {index + 1}/{questions.length}</span>
      <h3 className="text-2xl font-bold text-gray-800 mt-2 mb-6">{current.questionText}</h3>

      <div className="bg-blue-50 p-6 rounded-2xl mb-8 border-2 border-blue-100">
        <p className="text-3xl font-extrabold text-blue-600 leading-tight">{current.speakingTarget}</p>
      </div>

      <div className="mb-8 min-h-[5rem] bg-gray-50 rounded-xl p-4 border border-gray-100 flex items-center justify-center">
        {transcript ? (
            <p className="text-gray-700 text-lg font-medium">"{transcript}"</p>
        ) : (
            <p className="text-gray-400 italic text-sm">Nội dung bạn nói sẽ hiện ở đây...</p>
        )}
      </div>

      {feedback && <p className={`font-bold mb-4 animate-pulse ${feedback.includes('Tuyệt') ? 'text-green-600' : 'text-orange-500'}`}>{feedback}</p>}

      <div className="flex gap-4 justify-center items-center">
        <Button 
          onClick={toggleRecord} 
          variant={isListening ? 'danger' : 'primary'}
          size="lg"
          className={`rounded-full w-24 h-24 flex items-center justify-center transition-all ${isListening ? 'ring-4 ring-red-200 scale-110' : 'hover:scale-105'}`}
        >
          {isListening ? (
             <div className="flex flex-col items-center">
                <div className="w-8 h-8 bg-white rounded-sm animate-pulse"></div>
                <span className="text-[10px] mt-2 font-bold uppercase">Stop</span>
             </div>
          ) : (
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          )}
        </Button>
      </div>
      <p className="text-xs text-gray-400 mt-4">
          {isListening ? "Bấm nút vuông để DỪNG và kiểm tra" : "Bấm Micro để bắt đầu nói"}
      </p>

      <div className="mt-8 flex justify-center">
        <Button onClick={nextQuestion} variant="outline" size="sm">Bỏ qua (Skip)</Button>
      </div>
    </div>
  );
};

